/**
 * CLAWTRAP Full Architecture Simulation
 * ======================================
 * Faithfully implements: DFS maze gen, BFS pathfinding, Director Deck (30 cards),
 * card skip logic, HP management, pressure effects, trial system, exit conditions,
 * temptation mechanics, 66-step limit, God's Hand, Retreat.
 *
 * Reads: villain-content.json + player-decisions.json (generated by subagents)
 * Outputs: complete game log to stdout
 */
const fs = require('fs');
const path = require('path');

// ═══════════════════════════════════════════════════════════════
// SEEDED RNG (deterministic simulation)
// ═══════════════════════════════════════════════════════════════
let _seed = 42;
function rng() {
  _seed = (_seed * 16807 + 0) % 2147483647;
  return (_seed - 1) / 2147483646;
}
function rngInt(min, max) { return min + Math.floor(rng() * (max - min + 1)); }
function rngPick(arr) { return arr[Math.floor(rng() * arr.length)]; }

// ═══════════════════════════════════════════════════════════════
// MAZE GENERATION (DFS, identical to js/core.js)
// ═══════════════════════════════════════════════════════════════
const GRID_W = 21, GRID_H = 27;
const CELL_WALL = 0, CELL_PATH = 1, CELL_EXIT = 2;

function generateMaze() {
  const maze = Array.from({ length: GRID_H }, () => Array(GRID_W).fill(CELL_WALL));
  const stack = [{ x: 1, y: 1 }];
  maze[1][1] = CELL_PATH;

  while (stack.length > 0) {
    const { x, y } = stack[stack.length - 1];
    const dirs = [
      { dx: 0, dy: -2 }, { dx: 0, dy: 2 },
      { dx: -2, dy: 0 }, { dx: 2, dy: 0 },
    ].filter(d => {
      const nx = x + d.dx, ny = y + d.dy;
      return nx > 0 && nx < GRID_W - 1 && ny > 0 && ny < GRID_H - 1 && maze[ny][nx] === CELL_WALL;
    });

    if (dirs.length === 0) { stack.pop(); continue; }
    const d = dirs[Math.floor(rng() * dirs.length)];
    const nx = x + d.dx, ny = y + d.dy;
    maze[y + d.dy / 2][x + d.dx / 2] = CELL_PATH;
    maze[ny][nx] = CELL_PATH;
    stack.push({ x: nx, y: ny });
  }

  // Place exit at bottom-right area
  let exitX = GRID_W - 2, exitY = GRID_H - 2;
  if (maze[exitY][exitX] === CELL_WALL) {
    // Find nearest path cell to bottom-right
    for (let dy = 0; dy < GRID_H; dy++) {
      for (let dx = 0; dx < GRID_W; dx++) {
        const ty = GRID_H - 1 - dy, tx = GRID_W - 1 - dx;
        if (maze[ty][tx] === CELL_PATH) { exitX = tx; exitY = ty; dy = GRID_H; break; }
      }
    }
  }
  maze[exitY][exitX] = CELL_EXIT;
  return { maze, start: { x: 1, y: 1 }, exit: { x: exitX, y: exitY } };
}

// ═══════════════════════════════════════════════════════════════
// BFS PATHFINDING
// ═══════════════════════════════════════════════════════════════
function findPath(maze, start, end) {
  const key = (x, y) => `${x},${y}`;
  const queue = [{ ...start, path: [{ ...start }] }];
  const visited = new Set([key(start.x, start.y)]);

  while (queue.length > 0) {
    const { x, y, path: p } = queue.shift();
    if (x === end.x && y === end.y) return p;

    for (const [dx, dy] of [[0, -1], [0, 1], [-1, 0], [1, 0]]) {
      const nx = x + dx, ny = y + dy;
      if (nx < 0 || nx >= GRID_W || ny < 0 || ny >= GRID_H) continue;
      if (maze[ny][nx] === CELL_WALL) continue;
      const k = key(nx, ny);
      if (visited.has(k)) continue;
      visited.add(k);
      queue.push({ x: nx, y: ny, path: [...p, { x: nx, y: ny }] });
    }
  }
  return null; // no path found (shouldn't happen with DFS maze)
}

// Get neighbors (walkable adjacent cells)
function getNeighbors(maze, x, y) {
  const result = [];
  for (const [dx, dy, dir] of [[0, -1, 'N'], [0, 1, 'S'], [-1, 0, 'W'], [1, 0, 'E']]) {
    const nx = x + dx, ny = y + dy;
    if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H && maze[ny][nx] !== CELL_WALL) {
      result.push({ x: nx, y: ny, dir, dx, dy });
    }
  }
  return result;
}

