// ═══════════════════════════════════════════════════════════════
// SIMULATION ENGINE
// ═══════════════════════════════════════════════════════════════
const LOG = [];
function log(type, msg, detail = '') {
  const entry = { type, msg, detail };
  LOG.push(entry);
}

function runGame() {
  log('system', '═══════════════════════════════════════════════════');
  log('system', '  永久囚禁 · CLAWTRAP — 完整架构模拟');
  log('system', '═══════════════════════════════════════════════════');
  log('system', '');

  // 1. MAZE GENERATION
  const mazeData = generateMaze();
  const state = createGameState(mazeData);
  const shortestPath = findPath(mazeData.maze, mazeData.start, mazeData.exit);

  log('system', `[BOOT] 迷宫生成完毕: ${GRID_W}×${GRID_H}`);
  log('system', `[BOOT] 起点: (${mazeData.start.x},${mazeData.start.y})  出口: (${mazeData.exit.x},${mazeData.exit.y})`);
  log('system', `[BOOT] 最短路径长度: ${shortestPath ? shortestPath.length : 'N/A'} 步`);
  log('system', `[BOOT] HP: ${state.hp}/3  步数上限: 66`);
  log('system', `[BOOT] 出口解锁条件: 真相旗标≥${EXIT_CONDITIONS.minKnowledgeFlags} + 深度≥${EXIT_CONDITIONS.minDepth}`);
  log('system', '');

  // Player internal monologue
  const mono = playerDecisions.internal_monologue || {};
  log('player', `[内心] ${mono.game_start || '迷宫……开始了。'}`);
  log('system', '');

  // 2. GAME LOOP
  // Build a navigation path: follow shortest path but with occasional detours
  const navPath = buildNavigationPath(mazeData, shortestPath, state);
  let trialIdx = 0;
  let temptIdx = 0;
  let firstTrialDone = false;
  let firstHpLossDone = false;
  let depthMilestones = new Set();

  for (let moveIdx = 0; moveIdx < navPath.length && state.hp > 0 && state.steps < 66; moveIdx++) {
    const target = navPath[moveIdx];
    const isBack = state.history.length > 0 &&
      state.history[state.history.length - 1].x === target.x &&
      state.history[state.history.length - 1].y === target.y;

    // Update position
    if (!isBack) {
      state.history.push({ ...state.playerPos });
    } else {
      state.history.pop();
      state.backtrackCount++;
    }
    state.playerPos = { ...target };
    state.steps++;
    state.depth = state.history.length;
    state.visited.add(`${target.x},${target.y}`);
    state.deck.stepsSinceLastTrial++;

    // Track max depth
    if (state.depth > state._maxDepth) {
      state._maxDepth = state.depth;
      // Depth milestone reactions
      if (state.depth === 10 && !depthMilestones.has(10)) {
        depthMilestones.add(10);
        const speech10 = villainContent.speech?.depth_milestone?.['10'] || '你走得够深了。';
        log('villain', `[深度里程碑 d=10] ${speech10}`);
      }
      if (state.depth === 15 && !depthMilestones.has(15)) {
        depthMilestones.add(15);
        const speech15 = villainContent.speech?.depth_milestone?.['15'] || '回头的路比你想象的长。';
        log('villain', `[深度里程碑 d=15] ${speech15}`);
      }
    }

    // Tick pressure effects
    const effectsLog = tickEffects(state, isBack);
    if (effectsLog.hpLost) {
      if (!firstHpLossDone) {
        firstHpLossDone = true;
        log('player', `[内心] ${mono.first_hp_loss || '血量掉了……'}`);
      }
    }
    for (const el of effectsLog.entries) log(el.type, el.msg);
    if (state.hp <= 0) break;

    // 66-step check
    const stepsRemaining = 66 - state.steps;
    if (stepsRemaining <= 10 && stepsRemaining > 0) {
      log('system', `  ⚠ 剩余步数: ${stepsRemaining}/66`);
    }

    // Draw card
    const card = drawNextCard(state.deck);
    state.recentCards.push(card.role);
    if (state.recentCards.length > 10) state.recentCards.shift();

    // Card header
    const dist = Math.abs(state.playerPos.x - state.exitPos.x) + Math.abs(state.playerPos.y - state.exitPos.y);
    const distLabel = dist <= 4 ? '极近' : dist <= 8 ? '近' : dist <= 16 ? '中' : '远';
    log('system', `── Step ${state.steps} ──  pos(${state.playerPos.x},${state.playerPos.y})  depth=${state.depth}  HP=${state.hp}/3  exit=${distLabel}(${dist})  ${isBack ? '◄ 后退' : '► 前进'}`);
    log('system', `  [Deck #${state.deck.idx}] role=${card.role}  dealer=${card.dealer}${card.difficulty ? '  diff=' + card.difficulty : ''}${card.flag ? '  flag=' + card.flag : ''}`);

    // ── RESOLVE CARD ──
    resolveCard(card, state, isBack, () => trialIdx, (v) => { trialIdx = v; },
      () => temptIdx, (v) => { temptIdx = v; },
      firstTrialDone, (v) => { firstTrialDone = v; },
      firstHpLossDone, (v) => { firstHpLossDone = v; },
      mono);

    if (state.hp <= 0) break;

    // Check exit
    if (state.maze[state.playerPos.y][state.playerPos.x] === CELL_EXIT) {
      if (isExitUnlocked(state)) {
        log('system', '');
        log('system', '  ★★★ 玩家到达出口 — 出口已解锁！★★★');
        log('player', `[内心] ${mono.near_exit || '出口……我做到了。'}`);
        const epilogue = villainContent.speech?.endgame?.escaped || '你走了。但你看到的东西不会消失。';
        log('villain', `[终章] ${epilogue}`);
        state.mode = 'won';
        break;
      } else {
        const flags = countKnowledgeFlags(state);
        log('system', `  ✗ 出口被封印！真相旗标: ${flags}/${EXIT_CONDITIONS.minKnowledgeFlags}  深度: ${state.depth}/${EXIT_CONDITIONS.minDepth}`);
        log('villain', '  你找到了出口。但它不会为你打开。条件不够。');
        // Player needs to continue — add more path
        const extraPath = buildDetourPath(mazeData, state.playerPos, 15);
        navPath.push(...extraPath);
      }
    }

    log('system', '');
  }

  // 3. ENDGAME
  log('system', '');
  log('system', '═══════════════════════════════════════════════════');
  if (state.mode === 'won') {
    log('system', '  结局: 逃脱成功 (ESCAPED)');
  } else if (state.hp <= 0) {
    log('system', '  结局: 困死迷宫 (TRAPPED)');
    const epilogue = villainContent.speech?.endgame?.trapped || '游戏结束。';
    log('villain', `[终章] ${epilogue}`);
  } else if (state.steps >= 66) {
    log('system', '  结局: 迷失迷宫 (MAZE-LOST)');
    const epilogue = villainContent.speech?.endgame?.maze_lost || '你迷路了。';
    log('villain', `[终章] ${epilogue}`);
  } else {
    log('system', '  结局: 路径耗尽 (simulation ended)');
  }

  // Stats
  log('system', '═══════════════════════════════════════════════════');
  log('system', `  总步数: ${state.steps}/66`);
  log('system', `  最终HP: ${state.hp}/3`);
  log('system', `  最大深度: ${state._maxDepth}`);
  log('system', `  考验次数: ${state.trialCount} (通过=${state.trialPassCount} 失败=${state.trialFailCount})`);
  log('system', `  后退次数: ${state.backtrackCount}`);
  log('system', `  上帝之手: ${state.godHandCount}`);
  log('system', `  真相旗标: ${countKnowledgeFlags(state)}/4 [${Object.entries(state.deck.knowledgeFlags).filter(([k,v]) => v && k !== 'firstTrialDone').map(([k]) => k).join(', ')}]`);
  log('system', '═══════════════════════════════════════════════════');

  return LOG;
}

// ═══════════════════════════════════════════════════════════════
// CARD RESOLUTION
// ═══════════════════════════════════════════════════════════════
function resolveCard(card, state, isBack, getTrialIdx, setTrialIdx,
  getTempIdx, setTempIdx, firstTrialDone, setFirstTrialDone,
  firstHpLossDone, setFirstHpLossDone, mono) {

  const speeches = villainContent.speech || {};

  switch (card.role) {
    case 'relief': {
      const speech = rngPick(speeches.relief || ['……']);
      log('villain', `  ${speech}`);
      // 5% heal, 35% hint, 60% ambient
      const roll = rng();
      if (roll < 0.05 && state.hp < 3) {
        state.hp++;
        log('system', `  ♥ Relief回血! HP: ${state.hp}/3`);
      } else if (roll < 0.40) {
        const hintDir = getDirectionalHint(state);
        log('system', `  ◊ 方向线索: "${hintDir}"`);
      } else {
        log('system', '  ~ 环境叙事（安静的走廊）');
      }
      break;
    }

    case 'temptation': {
      const hook = rngPick(speeches.temptation_hook || ['墙上有什么东西……']);
      log('villain', `  ${hook}`);

      const tempIdx = getTempIdx();
      const tempDec = (playerDecisions.temptation_decisions || [])[tempIdx];
      setTempIdx(tempIdx + 1);

      const action = tempDec?.action || (rng() < 0.4 ? 'follow' : 'ignore');
      log('player', `  [决定] ${action === 'follow' ? '跟过去看看' : '无视，继续走'}${tempDec?.reasoning ? ' — ' + tempDec.reasoning : ''}`);

      if (action === 'follow') {
        const getsIntel = rng() < 0.5;
        if (getsIntel) {
          const hint = getDirectionalHint(state);
          log('system', `  → 跟随诱惑: 获得方向线索 "${hint}"`);
        } else {
          state.hp = Math.max(0, state.hp - 1);
          log('system', `  → 跟随诱惑: 陷阱！HP-1 → ${state.hp}/3`);
          if (!firstHpLossDone) {
            setFirstHpLossDone(true);
            log('player', `  [内心] ${mono.first_hp_loss || '该死……'}`);
          }
        }
      } else {
        state._avoidanceCount++;
        if (state._avoidanceCount % 3 === 0) {
          state.hp = Math.max(0, state.hp - 1);
          log('system', `  → 回避惩罚 (第${state._avoidanceCount}次回避): HP-1 → ${state.hp}/3`);
        } else {
          log('system', `  → 安全无视 (回避计数: ${state._avoidanceCount})`);
        }
      }
      break;
    }

    case 'pressure': {
      const speech = rngPick(speeches.pressure || ['……']);
      log('villain', `  ${speech}`);
      resolvePressure(card.dealer, state, isBack);
      break;
    }

    case 'trial': {
      const trialIdx = getTrialIdx();
      const trial = (villainContent.trials || [])[trialIdx] || villainContent.trials?.[0];
      setTrialIdx(trialIdx + 1);

      if (!firstTrialDone) {
        setFirstTrialDone(true);
        log('player', `  [内心] ${mono.first_trial || '要回答问题？'}`);
      }

      state.trialCount++;
      state.deck.stepsSinceLastTrial = 0;
      state.deck.knowledgeFlags.firstTrialDone = true;

      const openSpeech = rngPick(speeches.trial_open || ['回答我。']);
      log('villain', `  ${openSpeech}`);
      log('system', `  ┌─ Trial #${state.trialCount} [${card.difficulty}] ─────────────────`);
      log('system', `  │ Q: ${trial?.prompt || '你是谁？'}`);

      // Player answer
      const playerAnswer = (playerDecisions.trial_answers || [])[trialIdx];
      const answer = playerAnswer?.answer || '我不知道。';
      log('player', `  │ A: ${answer}`);

      // Judge (probabilistic based on difficulty)
      const passRates = { easy: 0.75, medium: 0.58, hard: 0.40 };
      const passRate = passRates[card.difficulty] || 0.55;
      // Adjust based on player confidence
      let adjustedRate = passRate;
      if (playerAnswer?.confidence === 'high') adjustedRate = Math.min(0.9, passRate + 0.15);
      if (playerAnswer?.confidence === 'low') adjustedRate = Math.max(0.15, passRate - 0.15);

      const passed = rng() < adjustedRate;

      if (passed) {
        state.trialPassCount++;
        const passSpeech = rngPick(speeches.trial_pass || ['过了。']);
        log('villain', `  │ [PASS] ${passSpeech}`);
        log('system', `  └─ 结果: 通过 ✓`);
      } else {
        state.trialFailCount++;
        const failSpeech = rngPick(speeches.trial_fail || ['错了。']);
        log('villain', `  │ [FAIL] ${failSpeech}`);

        // HP cost: trial 1 = no penalty, trial 2-3 = first fail costs 1, trial 4+ = every fail costs 1
        let hpCost = 0;
        if (state.trialCount >= 4) hpCost = 1;
        else if (state.trialCount >= 2) hpCost = 1;

        if (hpCost > 0 && state.hp > 0) {
          // Check if player uses God's Hand (HP=1 scenario or many fails)
          if (state.hp === 1) {
            // Player uses God's Hand at HP=1 to survive
            state.godHandCount++;
            state.hp = Math.max(0, state.hp - 1);
            const ghTaunt = rngPick(speeches.godhand_taunt || ['有意思。']);
            log('player', `  │ [上帝之手] 用生命跳过这道题`);
            log('villain', `  │ ${ghTaunt}`);
            log('system', `  └─ 结果: 上帝之手 — HP-1 → ${state.hp}/3`);
            if (!firstHpLossDone) {
              setFirstHpLossDone(true);
              log('player', `  [内心] ${mono.first_hp_loss || '血量……'}`);
            }
          } else {
            state.hp -= hpCost;
            log('system', `  └─ 结果: 失败 ✗ — HP-${hpCost} → ${state.hp}/3`);
            if (!firstHpLossDone) {
              setFirstHpLossDone(true);
              log('player', `  [内心] ${mono.first_hp_loss || '血量掉了。'}`);
            }
          }
        } else {
          log('system', `  └─ 结果: 失败 ✗ (首次考验, 不扣HP)`);
        }
      }

      // HP=1 warning
      if (state.hp === 1) {
        log('player', `  [内心] ${mono.low_hp || 'HP只剩1了……'}`);
      }
      break;
    }

    case 'truth': {
      if (card.flag && !state.deck.knowledgeFlags[card.flag]) {
        state.deck.knowledgeFlags[card.flag] = true;
        const truthSpeech = speeches.truth_reveal?.[card.flag] || '你发现了一个真相。';
        log('villain', `  [真相揭示: ${card.flag}]`);
        log('villain', `  ${truthSpeech}`);
        log('player', `  [内心] ${mono.truth_discovery || '原来如此……'}`);
        log('system', `  ◆ 真相旗标已获取: ${card.flag} (${countKnowledgeFlags(state)}/${EXIT_CONDITIONS.minKnowledgeFlags})`);

        // Check if exit just unlocked
        if (isExitUnlocked(state)) {
          log('system', '  ★ 出口解锁条件已满足！');
        }
      }
      break;
    }

    case 'payoff': {
      log('villain', '  ……休息吧。你赢得了喘息的机会。');
      if (state.hp < 3 && rng() < 0.6) {
        state.hp++;
        log('system', `  ♥ Payoff回血: HP+1 → ${state.hp}/3`);
        log('player', '  [决定] 选择休息，恢复体力。');
      } else {
        log('player', '  [决定] 谨慎地观察四周，继续前进。');
      }
      break;
    }
  }
}

// ═══════════════════════════════════════════════════════════════
// PRESSURE RESOLUTION
// ═══════════════════════════════════════════════════════════════
function resolvePressure(dealer, state, isBack) {
  const reactions = playerDecisions.pressure_reactions || {};

  switch (dealer) {
    case 'JUMPSCARE': {
      const movesInTime = reactions.JUMPSCARE?.movesInTime ?? (rng() < 0.78);
      if (movesInTime) {
        log('system', '  ⚡ JUMPSCARE — 玩家及时移动，无伤害');
        log('player', '  [反应] 心跳加速，但来得及躲开。');
      } else {
        state.hp = Math.max(0, state.hp - 1);
        log('system', `  ⚡ JUMPSCARE — 反应不及！HP-1 → ${state.hp}/3`);
        log('player', '  [反应] 太突然了……没来得及反应。');
      }
      break;
    }
    case 'WALL_CLOSE': {
      state.effects.wallCloseSteps = rngInt(2, 3);
      log('system', `  ▌ WALL_CLOSE — 一个方向被封锁 ${state.effects.wallCloseSteps} 步`);
      log('player', '  [反应] 墙壁在动……一条路被堵死了。');
      break;
    }
    case 'ECHO_LOOP': {
      state.effects.echoLoopSteps = rngInt(2, 3);
      log('system', `  ◎ ECHO_LOOP — 方向标识混乱 ${state.effects.echoLoopSteps} 步`);
      log('player', '  [反应] 所有方向标识都在闪烁……哪个是真的？');
      break;
    }
    case 'MEMORY_SCRAMBLE': {
      state.effects.memoryScrambleSteps = rngInt(2, 3);
      log('system', `  ◉ MEMORY_SCRAMBLE — 小地图失效 ${state.effects.memoryScrambleSteps} 步`);
      log('player', '  [反应] 地图消失了。只能凭感觉走。');
      break;
    }
    case 'SHADOW_CHASE': {
      state.effects.shadowChaseSteps = rngInt(2, 3);
      log('system', `  ▸ SHADOW_CHASE — 影子追踪 ${state.effects.shadowChaseSteps} 步 (后退=HP-1)`);
      log('player', '  [反应] 身后有东西在跟。绝对不能回头。');
      break;
    }
    case 'COUNTDOWN': {
      state.effects.countdownSteps = 8;
      state.effects.countdownStartDepth = state.depth;
      log('system', `  ⏱ COUNTDOWN — 8步内必须前进，否则HP-1`);
      log('player', '  [反应] 倒计时？！得赶紧往前走。');
      break;
    }
  }
}

// ═══════════════════════════════════════════════════════════════
// EFFECT TICK (each step)
// ═══════════════════════════════════════════════════════════════
function tickEffects(state, isBack) {
  const entries = [];
  let hpLost = false;

  if (state.effects.echoLoopSteps > 0) {
    state.effects.echoLoopSteps--;
    if (state.effects.echoLoopSteps === 0) entries.push({ type: 'system', msg: '  ◎ ECHO_LOOP 效果结束' });
  }
  if (state.effects.memoryScrambleSteps > 0) {
    state.effects.memoryScrambleSteps--;
    if (state.effects.memoryScrambleSteps === 0) entries.push({ type: 'system', msg: '  ◉ MEMORY_SCRAMBLE 效果结束' });
  }
  if (state.effects.wallCloseSteps > 0) {
    state.effects.wallCloseSteps--;
    if (state.effects.wallCloseSteps === 0) entries.push({ type: 'system', msg: '  ▌ WALL_CLOSE 效果结束' });
  }
  if (state.effects.shadowChaseSteps > 0) {
    if (isBack) {
      state.hp = Math.max(0, state.hp - 1);
      entries.push({ type: 'system', msg: `  ▸ SHADOW_CHASE: 后退受罚！HP-1 → ${state.hp}/3` });
      hpLost = true;
    }
    state.effects.shadowChaseSteps--;
    if (state.effects.shadowChaseSteps === 0) entries.push({ type: 'system', msg: '  ▸ SHADOW_CHASE 效果结束' });
  }
  if (state.effects.countdownSteps > 0) {
    state.effects.countdownSteps--;
    if (state.effects.countdownSteps === 0) {
      if (state.depth <= state.effects.countdownStartDepth) {
        state.hp = Math.max(0, state.hp - 1);
        entries.push({ type: 'system', msg: `  ⏱ COUNTDOWN: 未能前进！HP-1 → ${state.hp}/3` });
        hpLost = true;
      } else {
        entries.push({ type: 'system', msg: '  ⏱ COUNTDOWN: 成功前进！无惩罚' });
      }
    }
  }

  return { entries, hpLost };
}

// ═══════════════════════════════════════════════════════════════
// NAVIGATION HELPERS
// ═══════════════════════════════════════════════════════════════
function getDirectionalHint(state) {
  const dx = state.exitPos.x - state.playerPos.x;
  const dy = state.exitPos.y - state.playerPos.y;
  if (Math.abs(dx) > Math.abs(dy)) return dx > 0 ? '东方似乎有微光' : '西侧传来气流';
  return dy > 0 ? '南方的空气更流通' : '北面有回声';
}

function buildNavigationPath(mazeData, shortestPath, state) {
  if (!shortestPath || shortestPath.length === 0) return [];

  const path = [];
  const maze = mazeData.maze;

  // Follow shortest path but add realistic detours
  for (let i = 1; i < shortestPath.length && path.length < 55; i++) {
    // Occasionally take a wrong turn (15% chance), then backtrack
    if (rng() < 0.15 && i > 2 && i < shortestPath.length - 3) {
      const current = shortestPath[i - 1];
      const neighbors = getNeighbors(maze, current.x, current.y);
      const wrongTurns = neighbors.filter(n =>
        n.x !== shortestPath[i].x || n.y !== shortestPath[i].y
      );
      if (wrongTurns.length > 0) {
        const wrong = rngPick(wrongTurns);
        path.push({ x: wrong.x, y: wrong.y }); // wrong turn
        path.push({ x: current.x, y: current.y }); // backtrack to correct path
      }
    }
    path.push(shortestPath[i]);
  }

  return path;
}

function buildDetourPath(mazeData, from, steps) {
  const path = [];
  const maze = mazeData.maze;
  let pos = { ...from };
  const visited = new Set([`${pos.x},${pos.y}`]);

  for (let i = 0; i < steps; i++) {
    const neighbors = getNeighbors(maze, pos.x, pos.y);
    const unvisited = neighbors.filter(n => !visited.has(`${n.x},${n.y}`));
    const next = unvisited.length > 0 ? rngPick(unvisited) : (neighbors.length > 0 ? rngPick(neighbors) : null);
    if (!next) break;
    path.push({ x: next.x, y: next.y });
    visited.add(`${next.x},${next.y}`);
    pos = { x: next.x, y: next.y };
  }
  return path;
}

// ═══════════════════════════════════════════════════════════════
// RENDER LOG
// ═══════════════════════════════════════════════════════════════
function renderLog(entries) {
  const typeColors = {
    system: '',
    villain: '[恶意AI] ',
    player: '[玩家] ',
  };
  return entries.map(e => `${typeColors[e.type] || ''}${e.msg}`).join('\n');
}

