// MAIN
// ═══════════════════════════════════════════════════════════════
const gameLog = runGame();
const output = renderLog(gameLog);
console.log(output);

// Also save to file
const outPath = path.join(__dirname, 'game-log.txt');
fs.writeFileSync(outPath, output, 'utf-8');
console.log(`\n[saved to ${outPath}]`);
